          {(['All', 'Healthy', 'Issues'] as FilterType[]).map((type) => (
            <button
              key={type}
              onClick={() => setFilter(type)}
              className={`px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                filter === type
                  ? 'bg-green-100 text-green-800'
                  : 'text-gray-500 hover:text-gray-700'
